def is_anagram(sent1, sent2):
    sent1 = sent1.replace(" ", "").lower()
    sent2 = sent2.replace(" ", "").lower()

    if len(sent1) != len(sent2):
        return False

    counter = {}

    for letter in sent1:
        if letter in counter:
            counter[letter] += 1
        else:
            counter[letter] = 1

    for letter in sent2:
        if letter in counter:
            counter[letter] -= 1
        else:
            counter[letter] = 1

    for k in counter:
        if counter[k] != 0:
            return False

    return True

