import string
import random

def generate_password():
    letters = string.ascii_letters
    digits = string.digits
    symbols = string.punctuation
    all_chars = letters + digits + symbols

    password = "".join(random.choice(all_chars) for i in range(8))
    lower_count = 0
    upper_count = 0
    digit_count = 0

    for char in password:
        if char.islower():
            lower_count += 1
        elif char.isupper():
            upper_count += 1
        elif char.isdigit():
            digit_count += 1

    while lower_count == 0 or upper_count == 0 or digit_count == 0:
        password = "".join(random.choice(all_chars) for i in range(8))
        lower_count = 0
        upper_count = 0
        digit_count = 0
        for char in password:
            if char.islower():
                lower_count += 1
            elif char.isupper():
                upper_count += 1
            elif char.isdigit():
                digit_count += 1
    return password

