def bubble_sort(arr):
    # Base case
    if len(arr) == 1:
        return arr

    swapped = False
    for i in range(len(arr)-1):
        if arr[i] > arr[i+1]:
            arr[i], arr[i+1] = arr[i+1], arr[i] 
            swapped = True

    # Recursive call if items are swapped
    if swapped:
        return bubble_sort(arr)

    return arr

