def infix_to_postfix(infix_expr):
 stack = []
 output = []

 # Iterate through the characters of the expression
 for i in infix_expr:
 # Push opening brackets onto the stack
 if i == '(':
 stack.append(i)

 # Push operators onto the stack
 elif i in ['+', '-', '*', '/']:
 stack.append(i)

 # Pop and add to output when a closing bracket is found
 elif i == ')':
 while len(stack) != 0 and stack[-1] != '(':
 output.append(stack.pop()) 

 # Pop opening bracket
 if len(stack) != 0 and stack[-1] == '(':
 stack.pop()

 # Add numbers to output
 else:
 output.append(i)

 # Pop remaining operators on the stack
 while len(stack) != 0:
 output.append(stack.pop())

 return "".join(output)

